module counter_12
(
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
reg [1:0] state;
reg [1:0] next_state;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        out <= 4'b0000;
        state <= 2'b00;
    end
    else if (valid_count && out == 4'd11) begin
        out <= 4'b0000;
        state <= 2'b00;
    end
    else if (valid_count) begin
        out <= out + 4'b0001;
    end
end
endmodule
